// manageaddress.js - Address management functionality
import React, { useState, useEffect } from 'react';
import { NavLink } from 'react-router-dom';
import './manageaddress.css'; // Import CSS for address management
// This module handles address management for the profile page

const AccountNavigation = () => (
  <div className={styles.accountNavigationContainer}>
    <h3>Account Navigation</h3>
    <ul>
      <li>
        <NavLink to="/profile" className={({ isActive }) => isActive ? styles.active : ''}>
          Your Profile
        </NavLink>
      </li>
      <li>
        <NavLink to="/orders" className={({ isActive }) => isActive ? styles.active : ''}>
          Your Orders
        </NavLink>
      </li>
      <li>
        <NavLink to="/addresses" className={({ isActive }) => isActive ? styles.active : ''}>
          Your Addresses
        </NavLink>
      </li>
      <li>
        <NavLink to="/payments" className={({ isActive }) => isActive ? styles.active : ''}>
          Payment Methods
        </NavLink>
      </li>

      <li>
        <NavLink to="/account/help" className={({ isActive }) => isActive ? styles.active : ''}>
          Help & FAQ
        </NavLink>
      </li>
      {/* Add more navigation links here */}
    </ul>
  </div>
);

class AddressManager {
  constructor() {
    this.addresses = JSON.parse(localStorage.getItem('addresses')) || [];
    this.selectedAddress = null;
    this.editIndex = -1;
    this.setupEventListeners();
  }

  setupEventListeners() {
    // We'll set up event listeners after elements are available in the DOM
    // This will be called from the init method
  }

  initEventListeners() {
    // Add address form submission
    const addressForm = document.getElementById('address-form');
    if (addressForm) {
      addressForm.addEventListener('submit', (e) => {
        e.preventDefault();
        this.saveAddress();
      });
    }

    // Cancel button
    const cancelBtn = document.getElementById('cancel-btn');
    if (cancelBtn) {
      cancelBtn.addEventListener('click', () => {
        this.clearForm();
        this.toggleFormVisibility(false);
      });
    }

    // Add new address button
    const addAddressBtn = document.getElementById('add-address-btn');
    if (addAddressBtn) {
      addAddressBtn.addEventListener('click', () => {
        this.clearForm();
        this.editIndex = -1;
        this.toggleFormVisibility(true);
      });
    }
  }

  toggleFormVisibility(show) {
    const formContainer = document.getElementById('address-form-container');
    const addressList = document.getElementById('address-list-container');

    if (!formContainer || !addressList) return;

    if (show) {
      formContainer.classList.remove('hidden');
      addressList.classList.add('hidden');
    } else {
      formContainer.classList.add('hidden');
      addressList.classList.remove('hidden');
    }
  }

  saveAddress() {
    const nameInput = document.getElementById('name');
    const streetInput = document.getElementById('street');
    const cityInput = document.getElementById('city');
    const stateInput = document.getElementById('state');
    const zipcodeInput = document.getElementById('zipcode');
    const countryInput = document.getElementById('country');
    const defaultCheckbox = document.getElementById('default-address');

    if (!nameInput || !streetInput || !cityInput || !stateInput || !zipcodeInput || !countryInput || !defaultCheckbox) {
      console.error('Address form elements not found');
      return;
    }

    const address = {
      name: nameInput.value,
      street: streetInput.value,
      city: cityInput.value,
      state: stateInput.value,
      zipcode: zipcodeInput.value,
      country: countryInput.value,
      isDefault: defaultCheckbox.checked
    };

    if (this.validateAddress(address)) {
      if (this.editIndex >= 0) {
        // Update existing address
        this.addresses[this.editIndex] = address;
      } else {
        // Add new address
        this.addresses.push(address);
      }

      // If marked as default, update other addresses
      if (address.isDefault) {
        this.addresses.forEach((addr, idx) => {
          if (this.editIndex !== idx) {
            addr.isDefault = false;
          }
        });
      }

      // Make sure at least one address is default
      if (this.addresses.length === 1) {
        this.addresses[0].isDefault = true;
      }

      this.saveToLocalStorage();
      this.renderAddresses();
      this.clearForm();
      this.toggleFormVisibility(false);
    }
  }

  validateAddress(address) {
    // Basic validation
    if (!address.name || !address.street || !address.city || !address.state || !address.zipcode || !address.country) {
      alert('Please fill in all required fields');
      return false;
    }

    // Zip code validation - basic pattern for US
    if (address.country === 'United States' && !/^\d{5}(-\d{4})?$/.test(address.zipcode)) {
      alert('Please enter a valid ZIP code (12345 or 12345-6789)');
      return false;
    }

    return true;
  }

  editAddress(index) {
    const address = this.addresses[index];
    this.editIndex = index;

    const nameInput = document.getElementById('name');
    const streetInput = document.getElementById('street');
    const cityInput = document.getElementById('city');
    const stateInput = document.getElementById('state');
    const zipcodeInput = document.getElementById('zipcode');
    const countryInput = document.getElementById('country');
    const defaultCheckbox = document.getElementById('default-address');

    if (!nameInput || !streetInput || !cityInput || !stateInput || !zipcodeInput || !countryInput || !defaultCheckbox) {
      console.error('Address form elements not found');
      return;
    }

    // Populate form with address data
    nameInput.value = address.name;
    streetInput.value = address.street;
    cityInput.value = address.city;
    stateInput.value = address.state;
    zipcodeInput.value = address.zipcode;
    countryInput.value = address.country;
    defaultCheckbox.checked = address.isDefault;

    this.toggleFormVisibility(true);
  }

  deleteAddress(index) {
    // Use window.confirm instead of global confirm to fix ESLint error
    if (window.confirm('Are you sure you want to delete this address?')) {
      const wasDefault = this.addresses[index].isDefault;
      this.addresses.splice(index, 1);

      // If deleted address was default, set first remaining address as default
      if (wasDefault && this.addresses.length > 0) {
        this.addresses[0].isDefault = true;
      }

      this.saveToLocalStorage();
      this.renderAddresses();
    }
  }

  setDefaultAddress(index) {
    this.addresses.forEach((address, idx) => {
      address.isDefault = (idx === index);
    });

    this.saveToLocalStorage();
    this.renderAddresses();
  }

  clearForm() {
    const addressForm = document.getElementById('address-form');
    if (addressForm) {
      addressForm.reset();
    }
    this.editIndex = -1;
  }

  saveToLocalStorage() {
    localStorage.setItem('addresses', JSON.stringify(this.addresses));
  }

  renderAddresses() {
    const addressList = document.getElementById('address-list');
    if (!addressList) {
      console.error('Address list element not found');
      return;
    }

    addressList.innerHTML = '';

    if (this.addresses.length === 0) {
      addressList.innerHTML = '<div class="empty-state">No addresses saved. Add your first address.</div>';
      return;
    }

    this.addresses.forEach((address, index) => {
      const addressCard = document.createElement('div');
      addressCard.className = `address-card ${address.isDefault ? 'default-address' : ''}`;

      addressCard.innerHTML = `
        <div class="address-content">
          <h3>${address.name} ${address.isDefault ? '<span class="default-badge">Default</span>' : ''}</h3>
          <p>${address.street}</p>
          <p>${address.city}, ${address.state} ${address.zipcode}</p>
          <p>${address.country}</p>
        </div>
        <div class="address-actions">
          <button class="edit-btn" data-index="${index}">Edit</button>
          <button class="delete-btn" data-index="${index}">Delete</button>
          ${!address.isDefault ? `<button class="default-btn" data-index="${index}">Set as Default</button>` : ''}
        </div>
      `;

      addressList.appendChild(addressCard);
    });

    // Add event listeners to buttons
    document.querySelectorAll('.edit-btn').forEach(btn => {
      btn.addEventListener('click', (e) => {
        this.editAddress(parseInt(e.target.dataset.index));
      });
    });

    document.querySelectorAll('.delete-btn').forEach(btn => {
      btn.addEventListener('click', (e) => {
        this.deleteAddress(parseInt(e.target.dataset.index));
      });
    });

    document.querySelectorAll('.default-btn').forEach(btn => {
      btn.addEventListener('click', (e) => {
        this.setDefaultAddress(parseInt(e.target.dataset.index));
      });
    });
  }

  init() {
    // Check if elements exist, and if not, wait for them
    // This approach is more compatible with React's lifecycle
    if (document.getElementById('address-list')) {
      this.initEventListeners();
      this.renderAddresses();
    } else {
      // If elements aren't ready yet, set up a mutation observer
      // to detect when they become available
      const observer = new MutationObserver((mutations, obs) => {
        const addressList = document.getElementById('address-list');
        if (addressList) {
          this.initEventListeners();
          this.renderAddresses();
          obs.disconnect(); // Stop observing once we've initialized
        }
      });

      observer.observe(document.body, {
        childList: true,
        subtree: true
      });
    }
  }

  // Method to get the default address (used by other components)
  getDefaultAddress() {
    return this.addresses.find(address => address.isDefault) || null;
  }

  // Method to get all addresses (used by other components)
  getAllAddresses() {
    return this.addresses;
  }
}

// Export for use in other modules
export default AddressManager;
